Consider

```
union Value {
    1: string s
    2: i32 i
}

struct Foo { 1: optional Value value }
```

If now we add another field to `Value`,

```
union Value {
  // ...
  3: list<string> sList
}
```

And the server starts sending this in responses while the client is still running the older version of the Thrift file, `Value()` will be empty and fail with an error.

 A more desirable behavior for an empty Value might be to treat it as if it wasn't provided at all and let Foo decide whether it needs to fail based on whether Value is optional or required.

The issue from [Gitter]( https://gitter.im/pybind/Lobby?at=59b64c40319100804e1e054f)
## Reproducible example code
```c++
#include "pybind11/pybind11.h"
namespace py = pybind11;

struct BaseNonPolymorphic {
	unsigned int a;
	unsigned int b;
	unsigned int c;
	unsigned int d;
};
struct Derived : BaseNonPolymorphic {
	Derived() {
		a = 1;
		b = 2;
		c = 3;
		d = 4;
	};
	virtual ~Derived() {};
};
PYBIND11_MODULE(test_inheritance, m) {
	py::class_<BaseNonPolymorphic > base_class(m, "Base");
	base_class
		.def_readwrite("d", &BaseNonPolymorphic::d)
	;

	py::class_<Derived> derived_class(m, "Derived", base_class);
	derived_class
		.def(py::init<>())
	;
}
```

```python
import test_inheritance
derived_instance = test_inheritance.Derived()
assert derived_instance.d == 4
```

Consider the following example.
```C++
#include <pybind11/pybind11.h>
#include <iostream>

namespace py = pybind11;
using namespace pybind11::literals;

// classes
class objbase : public std::enable_shared_from_this< objbase > {
	int prop_ = 42;
public:
	virtual std::string name() const {
		return "objbase";
	}

	int prop() const { return prop_; }
};

class iface {
public:
	int n = 84;
	virtual int f() const = 0;
};

class mytype : public iface, public objbase {
public:
	std::string name() const override {
		return "mytype";
	}
	int f() const override {
		return 42;
	}
};
using sp_my = std::shared_ptr<mytype>;

// trampoline
template<class T = objbase>
class py_objbase : public T {
public:
	using T::T;

	std::string name() const override {
		PYBIND11_OVERLOAD(std::string, T, name);
	}
};

class py_iface : public iface {
public:
	using iface::iface;

	int f() const override {
		PYBIND11_OVERLOAD_PURE(int, iface, f);
	}
};

// bind mytype
class py_mytype : public py_iface, public py_objbase<mytype> {
public:
	int f() const override {
		PYBIND11_OVERLOAD(int, mytype, f);
	}
};

PYBIND11_PLUGIN(example) {
	py::module m("example");

	// bind objbase
	py::class_<objbase, py_objbase<>, std::shared_ptr<objbase>>(m, "objbase")
		.def(py::init<>())
		.def("name", &objbase::name)
		.def_property_readonly("prop", &objbase::prop)
		.def_property_readonly("refs", [](objbase& src) { return src.shared_from_this().use_count() - 1; })
	;

	// iface
	py::class_<iface, py_iface, std::shared_ptr<iface>>(m, "iface")
		.def("f", &iface::f)
	;

	// bind mytype
	py::class_<mytype, objbase, py_mytype, std::shared_ptr<mytype>>(m, "mytype")
		.def(py::init<>())
		.def("name", &mytype::name)
		.def("f", &mytype::f)
		.def_property_readonly("n", [](mytype& src){ return src.n; })
	;

	return m.ptr();
}
```
And now the Python test:
```Python
In [1]: import example

In [2]: a = example.mytype()

In [3]: a.prop
Out[3]: -95698912L

In [4]: a.refs
---------------------------------------------------------------------------
RuntimeError                              Traceback (most recent call last)
<ipython-input-4-344df654650d> in <module>()
----> 1 a.refs

RuntimeError: bad_weak_ptr
```
Calling `a.prop` and `a.refs` is UB, because parent `objbase` was *not constructed correctly*. I've had a hard time to figure out what is wrong with this bindings (can you see it?).

Yes -- I've forgot to mention `iface` in template args list of `class_<mytype, ...`. OK, let's fix that:
```C++
	py::class_<mytype, iface, objbase, py_mytype, std::shared_ptr<mytype>>(m, "mytype")
		.def(py::init<>())
		.def("name", &mytype::name)
		.def("f", &mytype::f)
		.def_property_readonly("n", [](mytype& src){ return src.n; })
	;
```
Now simple Python test succeeds:
```Python
In [2]: a = example.mytype()

In [3]: a.prop
Out[3]: 42L

In [4]: a.refs
Out[4]: 1L
```
Is that an expected behaviour? If I omit some of bases -- this is considered an error?
